An alternate version of zip() that can be used a bit more like python's version, and runs a bit faster.
```perl
use strict;
use warnings;
use Benchmark;
use AI::MXNet 'mx';

my @l1 = (0 .. 64);
my @l2 = (0 .. 64);
my @l3 = (0 .. 64);
my @l4 = (0 .. 64);

sub orig_zip
{
    my ($sub, @arrays) = @_;
    my $len = @{ $arrays[0] };
    for (my $i = 0; $i < $len; $i++)
    {
        $sub->(map { $_->[$i] } @arrays);
    }
}

Benchmark::cmpthese(-4, {
    orig => sub {
        my @l;
        orig_zip(sub {
            push @l, $_[0] + $_[1] + $_[2] + $_[3];
        }, \@l1, \@l2, \@l3, \@l4);
    },
    repl => sub {
        my @l;
        AI::MXNet::zip(sub {
            push @l, $_[0] + $_[1] + $_[2] + $_[3];
        }, \@l1, \@l2, \@l3, \@l4);
    },
    pure => sub {
        my @l = map { $_->[0] + $_->[1] + $_->[2] + $_->[3] }
            AI::MXNet::zip(\@l1, \@l2, \@l3, \@l4);
    },
});
```
gives

|    |   Rate|orig|repl|pure|
|----|-------|----|----|----|
|orig|21964/s|  --|-32%|-37%|
|repl|32190/s| 47%|  --| -7%|
|pure|34657/s| 58%|  8%|  --|
